var accounts = ["ACC-1001", "ACC-1002", "ACC-1003", "ACC-1004", "ACC-1005"];
var merchants = ["Retail", "Online", "ATM Withdrawal", "Travel", "Subscription"];
var forceHighRisk = (msg.payload === "force");

msg.payload = {
    transactionId: "TXN-" + Date.now(),
    accountId: accounts[Math.floor(Math.random() * accounts.length)],
    merchantCategory: merchants[Math.floor(Math.random() * merchants.length)],
    amount: forceHighRisk ? 5000 + Math.random() * 10000 : 10 + Math.random() * 500,
    velocity: forceHighRisk ? 8 + Math.floor(Math.random() * 5) : Math.floor(Math.random() * 3),
    locationMismatch: forceHighRisk ? 80 + Math.random() * 20 : Math.random() * 30,
    timeOfDayRisk: forceHighRisk ? 70 + Math.random() * 30 : Math.random() * 40,
    timestamp: new Date().toISOString()
};
return msg;

function triMF(x, a, b, c) {
    if (x <= a || x >= c) return 0;
    if (x === b) return 1;
    if (x < b) return (x - a) / (b - a);
    return (c - x) / (c - b);
}
function fuzzify(x, lowPts, medPts, highPts) {
    return {
        low: triMF(x, lowPts[0], lowPts[1], lowPts[2]),
        medium: triMF(x, medPts[0], medPts[1], medPts[2]),
        high: triMF(x, highPts[0], highPts[1], highPts[2])
    };
}

var t = msg.payload;
var amt = fuzzify(t.amount, [0, 0, 1000], [300, 1500, 3000], [2000, 15000, 15000]);
var vel = fuzzify(t.velocity, [0, 0, 3], [1, 4, 7], [5, 15, 15]);
var loc = fuzzify(t.locationMismatch, [0, 0, 40], [20, 50, 80], [60, 100, 100]);
var tod = fuzzify(t.timeOfDayRisk, [0, 0, 40], [20, 50, 80], [60, 100, 100]);

//normal: max of all normal rules
//warning: max of all warning rules
//critical: max of all critical rules
var rules = [
    { name: "Large amount combined with high transaction velocity", output: "critical", strength: Math.min(amt.high, vel.high) },
    { name: "Location mismatch or unusual transaction timing", output: "critical", strength: Math.max(loc.high, tod.high) },
    { name: "Moderate amount or velocity", output: "warning", strength: Math.max(amt.medium, vel.medium) },
    { name: "Mild location or timing irregularity", output: "warning", strength: Math.max(loc.medium, tod.medium) },
    { name: "All factors within normal range", output: "normal", strength: Math.min(amt.low, vel.low, loc.low, tod.low) }
];

var dominant = rules.reduce(function (a, b) { return b.strength > a.strength ? b : a; });
var agg = { normal: 0, warning: 0, critical: 0 };
rules.forEach(function (r) { agg[r.output] = Math.max(agg[r.output], r.strength); });

var points = { normal: 10, warning: 50, critical: 90 };
var num = agg.normal * points.normal + agg.warning * points.warning + agg.critical * points.critical;
var den = agg.normal + agg.warning + agg.critical;
var severity = den > 0 ? num / den : 0;

// Dynamic threshold — read live from flow context, set by the slider 
var criticalThreshold = flow.get('criticalThreshold') || 70;
var label = severity >= criticalThreshold ? "Critical" : severity >= 40 ? "Warning" : "Normal";

var reason = label === "Normal"
    ? "All risk factors within normal range"
    : dominant.name + " (rule strength " + dominant.strength.toFixed(2) + ")";

msg.payload = {
    transactionId: t.transactionId,
    accountId: t.accountId,
    merchantCategory: t.merchantCategory,
    amount: Math.round(t.amount * 100) / 100,
    velocity: t.velocity,
    locationMismatch: Math.round(t.locationMismatch),
    timeOfDayRisk: Math.round(t.timeOfDayRisk),
    riskScore: Math.round(severity),
    riskLabel: label,
    reason: reason,
    timestamp: t.timestamp
};
return msg;

var stats = flow.get('riskStats') || { total: 0, flagged: 0, totalScore: 0 };
stats.total += 1;
stats.totalScore += msg.payload.riskScore;
if (msg.payload.riskLabel !== "Normal") { stats.flagged += 1; }
flow.set('riskStats', stats);

msg.payload = {
    totalProcessed: stats.total,
    flaggedCount: stats.flagged,
    avgRiskScore: Math.round(stats.totalScore / stats.total)
};
return msg;

flow.set('riskStats', {
    total: 0,
    flagged: 0,
    totalScore: 0
});

return null;

var table = flow.get('flaggedTable') || [];
table.unshift({
    time: new Date(msg.payload.timestamp).toLocaleTimeString(),
    transactionId: msg.payload.transactionId,
    account: msg.payload.accountId,
    amount: "£" + msg.payload.amount.toFixed(2),
    score: msg.payload.riskScore,
    label: msg.payload.riskLabel,
    reason: msg.payload.reason
});
if (table.length > 15) table.pop();
flow.set('flaggedTable', table);
msg.payload = table;
return msg;

var t = msg.payload;

function esc(v) {
    return String(v === undefined || v === null ? "" : v).replace(/'/g, "''");
}

msg.payload = `
INSERT INTO IUGRED_15.RISK_AUDIT_LOG
(TRANSACTION_ID, ACCOUNT_ID, AMOUNT, RISK_SCORE, RISK_LABEL, REASON, CREATED_AT)
VALUES (
    '${esc(t.transactionId)}',
    '${esc(t.accountId)}',
    ${Number(t.amount).toFixed(2)},
    ${parseInt(t.riskScore, 10)},
    '${esc(t.riskLabel)}',
    '${esc(t.reason)}',
    CURRENT_TIMESTAMP
)
WITH NC
`;

return msg;

var t = msg.payload;

msg.topic = "🚨 Critical Risk Alert";
msg.payload =
    "Txn: " + t.transactionId +
    "\nAcc: " + t.accountId +
    "\nScore: " + t.riskScore + " (" + t.riskLabel + ")" +
    "\nAmount: £" + Number(t.amount).toFixed(2) +
    "\nReview Audit Log";

return msg;

flow.set('criticalThreshold', Number(msg.payload));

msg.topic = "⚙️ Risk Threshold Updated";
msg.payload = "New critical threshold: " + msg.payload;

return msg;

msg.payload = `
ALTER TABLE IUGRED_15.RISK_AUDIT_LOG
ADD COLUMN REVIEWED_AT TIMESTAMP
`;
return msg;

var form = msg.payload || {};

function clean(v) {
    return String(v === undefined || v === null ? "" : v).trim();
}

var txnId = clean(form.TransactionID);
var disposition = clean(form.Disposition);
var notes = clean(form.AnalystNotes);

var allowed = [
    "Confirmed Fraud",
    "False Positive",
    "Needs Escalation"
];

// Validation: Transaction ID and Disposition required
if (!txnId || !disposition) {
    return [
        {
            topic: "⚠️ Review Not Saved",
            payload: "Please enter both Transaction ID and Disposition."
        },
        null
    ];
}

// Validation: only allow known disposition values
if (allowed.indexOf(disposition) === -1) {
    return [
        {
            topic: "⚠️ Invalid Disposition",
            payload: "Use one of: Confirmed Fraud, False Positive, Needs Escalation."
        },
        null
    ];
}

var info = {
    transactionId: txnId,
    disposition: disposition,
    notes: notes
};

// Output 1 -> notification path
var msg1 = {
    dispositionInfo: info
};

// Output 2 -> DB2 update path
var msg2 = {
    dispositionInfo: info
};

return [msg1, msg2];

var d = msg.dispositionInfo;

msg.topic = "✅ Disposition Recorded";
msg.payload =
    "Transaction " + d.transactionId +
    "\nDisposition: " + d.disposition +
    (d.notes ? "\nNotes saved successfully." : "\nNo notes provided.");

return msg;

var d = msg.dispositionInfo;

function esc(v) {
    return String(v === undefined || v === null ? "" : v).replace(/'/g, "''");
}

msg.payload = `
UPDATE IUGRED_15.RISK_AUDIT_LOG
SET DISPOSITION = '${esc(d.disposition)}',
    ANALYST_NOTES = '${esc(d.notes)}',
    REVIEWED_AT = CURRENT_TIMESTAMP
WHERE TRANSACTION_ID = '${esc(d.transactionId)}'
WITH NC
`;

return msg;

var rows = msg.payload || [];
function badge(label) {
    var cls = label === "Critical" ? "badge-critical" : label === "Warning" ? "badge-warning" : "badge-normal";
    return '<span class="badge ' + cls + '">' + label + '</span>';
}
var html = rows.map(function(r) {
    return '<tr>' +
        '<td>' + r.time + '</td>' +
        '<td class="mono">' + r.transactionId + '</td>' +
        '<td>' + r.account + '</td>' +
        '<td>' + r.amount + '</td>' +
        '<td class="score">' + r.score + '</td>' +
        '<td>' + badge(r.label) + '</td>' +
        '<td class="reason">' + r.reason + '</td>' +
    '</tr>';
}).join('');

msg.payload = html || '<tr><td colspan="7" class="empty">No flagged transactions yet</td></tr>';
return msg;

var t = msg.payload;
var alerts = flow.get('criticalAlerts') || [];
alerts.unshift({
    time: new Date(t.timestamp).toLocaleTimeString(),
    transactionId: t.transactionId,
    account: t.accountId,
    amount: Number(t.amount).toFixed(2),
    score: t.riskScore,
    reason: t.reason
});
if (alerts.length > 5) alerts.pop();
flow.set('criticalAlerts', alerts);

var html = alerts.map(function(a) {
    return '<div class="alert-item">' +
        '<div class="alert-top"><span class="alert-score">' + a.score + '</span>' +
        '<span class="alert-txn">' + a.transactionId + '</span>' +
        '<span class="alert-time">' + a.time + '</span></div>' +
        '<div class="alert-body">' + a.account + ' &middot; \u00a3' + a.amount + '</div>' +
        '<div class="alert-reason">' + a.reason + '</div>' +
    '</div>';
}).join('');

msg.payload = html || '<div class="alert-empty">No critical alerts</div>';
return msg;

msg.payload =
`CREATE TABLE IUGRED_15.ANALYST_REVIEW_LOG (
  REVIEW_ID      INT GENERATED ALWAYS AS IDENTITY,
  TRANSACTION_ID VARCHAR(30),
  ACCOUNT_ID     VARCHAR(20),
  DISPOSITION    VARCHAR(30),
  ANALYST_NOTES  VARCHAR(500),
  REVIEWED_AT    TIMESTAMP
)`;

return msg;

var d = msg.dispositionInfo;

function esc(v) {
    return String(v === undefined || v === null ? "" : v).replace(/'/g, "''");
}

// look up account id from the flagged table cache if available
var table = flow.get('flaggedTable') || [];
var match = table.find(function(r) { return r.transactionId === d.transactionId; });
var accountId = match ? match.account : "";

msg.payload = `
INSERT INTO IUGRED_15.ANALYST_REVIEW_LOG
(TRANSACTION_ID, ACCOUNT_ID, DISPOSITION, ANALYST_NOTES, REVIEWED_AT)
VALUES (
    '${esc(d.transactionId)}',
    '${esc(accountId)}',
    '${esc(d.disposition)}',
    '${esc(d.notes)}',
    CURRENT_TIMESTAMP
)
WITH NC
`;
return msg;

var d = msg.dispositionInfo;
var log = flow.get('reviewLogDisplay') || [];
log.unshift({
    time: new Date().toLocaleTimeString(),
    transactionId: d.transactionId,
    disposition: d.disposition,
    notes: d.notes || '(no notes)'
});
if (log.length > 10) log.pop();
flow.set('reviewLogDisplay', log);

function badge(disp) {
    var cls = disp === "Confirmed Fraud" ? "badge-fraud" :
        disp === "False Positive" ? "badge-false" : "badge-escalate";
    return '<span class="badge ' + cls + '">' + disp + '</span>';
}

var html = log.map(function (r) {
    return '<tr>' +
        '<td>' + r.time + '</td>' +
        '<td class="mono">' + r.transactionId + '</td>' +
        '<td>' + badge(r.disposition) + '</td>' +
        '<td class="notes">' + r.notes + '</td>' +
        '</tr>';
}).join('');

msg.payload = html || '<tr><td colspan="4" class="empty">No reviews submitted yet</td></tr>';
return msg;
